using System;

class Program {
    static void Main() {
        for (int i = 1; i <= 5; i++) {
            Console.WriteLine(i);
        }
    }
}

using System;

class Program {
    static void Main() {
        for (int i = 5; i >= 1; i--) {
            Console.WriteLine(i);
        }
        Console.WriteLine("Go!");
    }
}

using System;

class Program {
    static void Main() {
        int n = 1;
        while (n <= 100) {
            n *= 2;
        }
        Console.WriteLine(n);
    }
}

using System;

class Program {
    static void Main() {
        int count = 0;
        do {
            Console.WriteLine($"count: {count}");
            count++;
        } while (count < 3);
    }
}

using System;

class Program {
    static void Main() {
        string[] langs = { "Go", "Rust", "C#", "Python" };
        foreach (string lang in langs) {
            Console.WriteLine(lang);
        }
    }
}

using System;

class Program {
    static void Main() {
        for (int i = 1; i <= 10; i++) {
            if (i % 3 == 0) continue;
            if (i > 7) break;
            Console.Write($"{i} ");
        }
        Console.WriteLine();
    }
}

using System;

class Program {
    static void Main() {
        for (int row = 1; row <= 3; row++) {
            for (int col = 1; col <= 3; col++) {
                Console.Write($"{row*col} ");
            }
            Console.WriteLine();
        }
    }
}

using System;
using System.Linq;

class Program {
    static void Main() {
        var squares = Enumerable.Range(1, 5).Select(i => i * i);
        foreach (var s in squares) {
            Console.Write($"{s} ");
        }
        Console.WriteLine();
    }
}
